services.resolved = {
  enable = true;
  settings = {
    Resolve = {
      DNSSEC = "true";
      # ".lan" is served per-link on br0 (see the split-dns service below),
      # so only the catch-all routing domain lives here.
      Domains = [ "~." ];
      FallbackDNS = [
        "1.1.1.1#one.one.one.one"
        "1.0.0.1#one.one.one.one"
      ];
      DNSOverTLS = "true";
    };
  };
};

# Split-DNS: resolve the "lan" zone via the local router instead of the
# global DoT servers. br0 is scripted networking (not networkd), so we can't
# use a .network file — bind the per-link DNS/domain via resolvectl once the
# interface and systemd-resolved are up. "lan" (no tilde) is both a search
# suffix and a routing domain; DNSSEC is auto-skipped for this private zone.
systemd.services.split-dns-lan = {
  description = "Route .lan queries to the local DNS on br0";
  after = [
    "systemd-resolved.service"
    "sys-subsystem-net-devices-br0.device"
  ];
  requires = [ "systemd-resolved.service" ];
  bindsTo = [ "sys-subsystem-net-devices-br0.device" ];
  wantedBy = [ "sys-subsystem-net-devices-br0.device" ];
  serviceConfig = {
    Type = "oneshot";
    RemainAfterExit = true;
    ExecStart = [
      "${pkgs.systemd}/bin/resolvectl dns br0 192.168.152.1"
      "${pkgs.systemd}/bin/resolvectl domain br0 lan"
    ];
  };
};

