# Split-DNS for the "lan" zone. The global resolver enforces DNSOverTLS
# (strict), which the local router at 192.168.152.1 does not speak — so .lan
# queries would silently fall back to the DoT upstream and NXDOMAIN. br0 is
# scripted networking (not networkd), so bind the per-link resolver settings
# via resolvectl once the network is up: local DNS, "lan" as search+routing
# domain, and DoT disabled for this link only. Anchored to network-online +
# multi-user (not the br0 .device): the device is already plugged at switch
# time, so a .device "want" never fires and the unit would stay dead.
systemd.services.split-dns-lan = {
  description = "Route .lan queries to the local DNS on br0 (no DoT)";
  after = [
    "systemd-resolved.service"
    "network-online.target"
  ];
  wants = [ "network-online.target" ];
  requires = [ "systemd-resolved.service" ];
  wantedBy = [ "multi-user.target" ];
  serviceConfig = {
    Type = "oneshot";
    RemainAfterExit = true;
    ExecStart = [
      "${pkgs.systemd}/bin/resolvectl dns br0 192.168.152.1"
      "${pkgs.systemd}/bin/resolvectl domain br0 lan"
      "${pkgs.systemd}/bin/resolvectl dnsovertls br0 no"
    ];
  };
};

